import { AuthUser, UserRole } from '../types';

const USERS_KEY = 'masari_users';

// Initialize default owner if not exists
const initAuth = () => {
  const users = getUsers();
  if (!users.find(u => u.role === 'owner')) {
    const owner: AuthUser & { password: string } = {
      id: 'owner-1',
      username: 'admin',
      password: 'admin123', // In a real app, this should be hashed
      name: 'مدير النظام',
      role: 'owner',
      createdAt: new Date().toISOString()
    };
    users.push(owner);
    saveUsers(users);
  }
};

const getUsers = (): any[] => {
  try {
    return JSON.parse(localStorage.getItem(USERS_KEY) || '[]');
  } catch {
    return [];
  }
};

const saveUsers = (users: any[]) => {
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
};

export const loginUser = (username: string, password: string): AuthUser | null => {
  initAuth();
  const users = getUsers();
  const user = users.find(u => u.username === username && u.password === password);
  if (user) {
    const { password, ...userWithoutPass } = user;
    return userWithoutPass;
  }
  return null;
};

export const registerStudent = (data: { name: string; email: string; password: string; phone: string }) => {
  const users = getUsers();
  if (users.find(u => u.username === data.email)) {
    throw new Error('البريد الإلكتروني مسجل مسبقاً');
  }

  const newUser = {
    id: Date.now().toString(),
    username: data.email,
    password: data.password,
    name: data.name,
    phone: data.phone,
    role: 'student' as UserRole,
    createdAt: new Date().toISOString()
  };

  users.push(newUser);
  saveUsers(users);

  const { password, ...userWithoutPass } = newUser;
  return userWithoutPass;
};

export const createAdmin = (currentAdmin: AuthUser, data: { username: string; password: string; name: string }) => {
  if (currentAdmin.role !== 'owner') {
    throw new Error('غير مصرح لك بإضافة مسؤولين');
  }

  const users = getUsers();
  if (users.find(u => u.username === data.username)) {
    throw new Error('اسم المستخدم مستخدم مسبقاً');
  }

  const newAdmin = {
    id: Date.now().toString(),
    username: data.username,
    password: data.password,
    name: data.name,
    role: 'admin' as UserRole,
    createdAt: new Date().toISOString()
  };

  users.push(newAdmin);
  saveUsers(users);
  return newAdmin;
};

export const updateProfile = (userId: string, data: { name?: string; password?: string; phone?: string }) => {
  const users = getUsers();
  const index = users.findIndex(u => u.id === userId);
  if (index === -1) throw new Error('المستخدم غير موجود');

  if (data.name) users[index].name = data.name;
  if (data.password) users[index].password = data.password;
  if (data.phone) users[index].phone = data.phone;

  saveUsers(users);

  const { password, ...updatedUser } = users[index];
  return updatedUser;
};

export const getAllAdmins = (currentAdmin: AuthUser) => {
  if (currentAdmin.role !== 'owner') return [];
  return getUsers().filter(u => u.role === 'admin').map(({ password, ...u }) => u);
};

import React, { useState, useCallback, useEffect } from 'react';
import { Header } from './components/Header';
import { Hero } from './components/Hero';
import { AssessmentForm } from './components/AssessmentForm';
import { ResultsDashboard } from './components/ResultsDashboard';
import { AdminDashboard } from './components/AdminDashboard';
import { AuthModal } from './components/AuthModal';
import { StudentProfile } from './components/StudentProfile';
import { UserProfile, MajorRecommendation, AuthUser } from './types';
import { generateRecommendations } from './services/gemini';
import { saveSubmission } from './services/storage';
import { Loader2, Code2, MapPin, Mail, Globe } from 'lucide-react';

// Initial empty state
const initialUserProfile: UserProfile = {
  name: '',
  email: '',
  phone: '',
  address: '',
  schoolName: '',
  academicStrengths: [],
  interests: [],
  softSkills: [],
  workPreference: '',
  environmentPreference: ''
};

function App() {
  const [view, setView] = useState<'hero' | 'assessment' | 'loading' | 'results' | 'admin' | 'student-profile'>('hero');
  const [userProfile, setUserProfile] = useState<UserProfile>(initialUserProfile);
  const [recommendations, setRecommendations] = useState<MajorRecommendation[]>([]);
  const [error, setError] = useState<string | null>(null);

  // Auth State
  const [currentUser, setCurrentUser] = useState<AuthUser | null>(null);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);

  // Check for session (simple persistence via memory, in real app check token)
  useEffect(() => {
    // If we wanted session persistence across reloads, we'd check localStorage here
    // keeping it simple per request scope
  }, []);

  const handleStart = () => {
    // If student is logged in, pre-fill data
    if (currentUser && currentUser.role === 'student') {
        setUserProfile(prev => ({
            ...prev,
            userId: currentUser.id,
            name: currentUser.name,
            email: currentUser.username,
            phone: currentUser.phone || '',
        }));
    }
    setView('assessment');
    window.scrollTo(0, 0);
  };

  const handleProfileUpdate = useCallback((updates: Partial<UserProfile>) => {
    setUserProfile(prev => ({ ...prev, ...updates }));
  }, []);

  const handleSubmitAssessment = async () => {
    setView('loading');
    setError(null);
    try {
      const results = await generateRecommendations(userProfile);
      setRecommendations(results);

      // Save data automatically
      // Ensure user ID is attached if logged in
      const profileToSave = currentUser ? { ...userProfile, userId: currentUser.id } : userProfile;
      saveSubmission(profileToSave, results);

      setView('results');
    } catch (err) {
      console.error(err);
      setError("حدث خطأ أثناء تحليل البيانات. يرجى المحاولة مرة أخرى.");
      setView('assessment'); 
    }
  };

  const handleRestart = () => {
    // Keep user info if logged in, otherwise reset
    if (currentUser && currentUser.role === 'student') {
         setUserProfile({
            ...initialUserProfile,
            userId: currentUser.id,
            name: currentUser.name,
            email: currentUser.username,
            phone: currentUser.phone || '',
         });
    } else {
        setUserProfile(initialUserProfile);
    }
    setRecommendations([]);
    setView('hero');
    window.scrollTo(0, 0);
  };

  // Auth Handlers
  const handleLogin = (user: AuthUser) => {
    setCurrentUser(user);
    if (user.role === 'admin' || user.role === 'owner') {
      setView('admin');
    } else {
      setView('hero');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    setUserProfile(initialUserProfile);
    setView('hero');
  };

  const handleUserUpdate = (updatedUser: AuthUser) => {
    setCurrentUser(updatedUser);
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 font-sans flex flex-col" dir="rtl">
      <Header 
        currentUser={currentUser}
        onLoginClick={() => setIsAuthModalOpen(true)}
        onLogoutClick={handleLogout}
        onProfileClick={() => setView('student-profile')}
        onAdminDashboardClick={() => setView('admin')}
      />

      <AuthModal 
        isOpen={isAuthModalOpen} 
        onClose={() => setIsAuthModalOpen(false)} 
        onLogin={handleLogin}
      />

      <main className="flex-grow">
        {view === 'hero' && (
          <Hero onStart={handleStart} />
        )}

        {view === 'admin' && currentUser && (currentUser.role === 'admin' || currentUser.role === 'owner') && (
          <AdminDashboard 
            currentUser={currentUser} 
            onLogout={handleLogout} 
          />
        )}

        {view === 'student-profile' && currentUser && (
          <StudentProfile 
            user={currentUser} 
            onBack={() => setView('hero')} 
            onUpdate={handleUserUpdate}
          />
        )}

        {view === 'assessment' && (
          <div className="animate-fadeIn">
            <AssessmentForm 
              data={userProfile} 
              onChange={handleProfileUpdate} 
              onSubmit={handleSubmitAssessment} 
            />
            {error && (
              <div className="max-w-md mx-auto mt-4 p-4 bg-red-50 text-red-700 border border-red-200 rounded-lg text-center">
                {error}
              </div>
            )}
          </div>
        )}

        {view === 'loading' && (
          <div className="flex flex-col items-center justify-center min-h-[calc(100vh-64px)]">
            <Loader2 className="w-16 h-16 text-indigo-600 animate-spin mb-6" />
            <h2 className="text-2xl font-bold text-gray-800">جاري تحليل بياناتك...</h2>
            <p className="text-gray-500 mt-2">يقوم الذكاء الاصطناعي بدراسة ملفك لمطابقة أفضل التخصصات</p>

            <div className="mt-8 max-w-sm w-full bg-gray-200 rounded-full h-2.5 dark:bg-gray-200 overflow-hidden">
              <div className="bg-indigo-600 h-2.5 rounded-full animate-[loading_2s_ease-in-out_infinite] w-[50%]"></div>
            </div>
            <style>{`
              @keyframes loading {
                0% { transform: translateX(150%); }
                100% { transform: translateX(-150%); }
              }
            `}</style>
          </div>
        )}

        {view === 'results' && (
          <div className="animate-fadeIn">
            <ResultsDashboard 
              user={userProfile} 
              recommendations={recommendations} 
              onRestart={handleRestart}
            />
          </div>
        )}
      </main>

      {view !== 'admin' && view !== 'student-profile' && (
        <footer className="bg-slate-900 text-slate-300 border-t border-slate-800 mt-20">
          <div className="max-w-7xl mx-auto py-12 px-4 sm:px-6 lg:px-8">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-center">

              {/* Company Info */}
              <div className="space-y-6">
                <div className="flex items-center gap-3">
                  <div className="p-3 bg-indigo-600 rounded-lg">
                    <Code2 className="w-8 h-8 text-white" />
                  </div>
                  <div>
                    <h3 className="text-2xl font-bold text-white">Black Pharaohs Code</h3>
                    <p className="text-sm text-indigo-400 font-medium">شركة بلاك فاروز كود البرمجية</p>
                  </div>
                </div>
                <p className="text-base leading-relaxed max-w-md text-slate-400">
                  شركة برمجية رائدة متخصصة في تطوير الحلول التقنية المبتكرة والأنظمة التعليمية الذكية. 
                  نحن نؤمن بقوة التكنولوجيا في رسم مستقبل أفضل للطلاب وتمكينهم من تحقيق أهدافهم الأكاديمية والمهنية.
                </p>
              </div>

              {/* Contact / Links */}
              <div className="md:border-r md:border-slate-800 md:pr-12 space-y-6">
                <h4 className="text-lg font-bold text-white">تواصل معنا</h4>
                <ul className="space-y-4">
                  <li className="flex items-center gap-3">
                    <MapPin className="w-5 h-5 text-indigo-500" />
                    <span>الخرطوم، السودان - المقر الرئيسي</span>
                  </li>
                  <li className="flex items-center gap-3">
                    <Mail className="w-5 h-5 text-indigo-500" />
                    <span>contact@blackpharaohs.code</span>
                  </li>
                  <li className="flex items-center gap-3">
                    <Globe className="w-5 h-5 text-indigo-500" />
                    <span>www.blackpharaohs-code.com</span>
                  </li>
                </ul>
              </div>
            </div>

            <div className="mt-12 pt-8 border-t border-slate-800 text-center text-sm text-slate-500">
              © {new Date().getFullYear()} ألارا - جميع الحقوق محفوظة لشركة Black Pharaohs Code.
            </div>
          </div>
        </footer>
      )}
    </div>
  );
}

export default App;

import React, { useEffect, useState } from 'react';
import { AuthUser } from '../types';
import { getSubmissions, Submission } from '../services/storage';
import { updateProfile } from '../services/auth';
import { User, Calendar, BookOpen, Mail, Edit2, Save, X, Phone, Lock } from 'lucide-react';

interface StudentProfileProps {
  user: AuthUser;
  onBack: () => void;
  onUpdate: (user: AuthUser) => void;
}

export const StudentProfile: React.FC<StudentProfileProps> = ({ user, onBack, onUpdate }) => {
  const [history, setHistory] = useState<Submission[]>([]);
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    name: user.name,
    phone: user.phone || '',
    password: ''
  });
  const [msg, setMsg] = useState({ text: '', type: '' });

  useEffect(() => {
    // Filter submissions for this student (matched by name/email in local storage simulation)
    const all = getSubmissions();
    const mySubmissions = all.filter(
      s => (s.profile.userId === user.id) || (s.profile.email === user.username)
    );
    setHistory(mySubmissions);
  }, [user]);

  // Reset form when entering edit mode or when user changes
  useEffect(() => {
    setFormData({
      name: user.name,
      phone: user.phone || '',
      password: ''
    });
    setMsg({ text: '', type: '' });
  }, [user, isEditing]);

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const updatedUser = updateProfile(user.id, {
        name: formData.name,
        phone: formData.phone,
        password: formData.password || undefined
      });
      onUpdate(updatedUser);
      setIsEditing(false);
      setMsg({ text: 'تم تحديث البيانات بنجاح', type: 'success' });
      setTimeout(() => setMsg({ text: '', type: '' }), 3000);
    } catch (err: any) {
      setMsg({ text: err.message, type: 'error' });
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-10 animate-fadeIn">
      <div className="flex justify-between items-center mb-8">
        <h2 className="text-2xl font-bold text-gray-900">الملف الشخصي للطالب</h2>
        <button onClick={onBack} className="text-gray-500 hover:text-indigo-600">
          العودة للرئيسية
        </button>
      </div>

      {msg.text && (
        <div className={`mb-6 p-4 rounded-lg border ${msg.type === 'success' ? 'bg-green-50 border-green-200 text-green-700' : 'bg-red-50 border-red-200 text-red-700'}`}>
          {msg.text}
        </div>
      )}

      <div className="bg-white rounded-2xl shadow-lg overflow-hidden mb-8">
        <div className="bg-indigo-600 h-32 relative">
          <div className="absolute -bottom-10 right-8">
             <div className="w-24 h-24 bg-white rounded-full p-2 shadow-lg">
                <div className="w-full h-full bg-indigo-100 rounded-full flex items-center justify-center">
                    <User className="w-10 h-10 text-indigo-600" />
                </div>
             </div>
          </div>
          <div className="absolute top-4 left-4">
             <button 
                onClick={() => setIsEditing(!isEditing)}
                className="flex items-center gap-2 bg-white/20 backdrop-blur-sm text-white px-4 py-2 rounded-lg hover:bg-white/30 transition-colors"
             >
                {isEditing ? (
                  <>
                    <X className="w-4 h-4" />
                    <span>إلغاء</span>
                  </>
                ) : (
                  <>
                    <Edit2 className="w-4 h-4" />
                    <span>تعديل البيانات</span>
                  </>
                )}
             </button>
          </div>
        </div>

        <div className="pt-12 px-8 pb-8">
          {isEditing ? (
            <form onSubmit={handleSave} className="space-y-4 max-w-lg">
               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">الاسم الكامل</label>
                 <div className="relative">
                   <User className="absolute right-3 top-3 w-5 h-5 text-gray-400" />
                   <input
                     type="text"
                     value={formData.name}
                     onChange={e => setFormData({...formData, name: e.target.value})}
                     className="w-full pr-10 pl-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500"
                     required
                   />
                 </div>
               </div>

               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">رقم الهاتف</label>
                 <div className="relative">
                   <Phone className="absolute right-3 top-3 w-5 h-5 text-gray-400" />
                   <input
                     type="tel"
                     value={formData.phone}
                     onChange={e => setFormData({...formData, phone: e.target.value})}
                     className="w-full pr-10 pl-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500"
                   />
                 </div>
               </div>

               <div>
                 <label className="block text-sm font-medium text-gray-700 mb-1">
                    كلمة المرور الجديدة 
                    <span className="text-xs font-normal text-gray-500 mr-1">(اتركها فارغة إذا لم ترد التغيير)</span>
                 </label>
                 <div className="relative">
                   <Lock className="absolute right-3 top-3 w-5 h-5 text-gray-400" />
                   <input
                     type="password"
                     value={formData.password}
                     onChange={e => setFormData({...formData, password: e.target.value})}
                     className="w-full pr-10 pl-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500"
                     minLength={6}
